@prefix dcterms: <http://purl.org/dc/terms/> .
@prefix sh: <http://www.w3.org/ns/shacl#> .
@prefix xsd: <http://www.w3.org/2001/XMLSchema#> .

[] a sh:ValidationReport ;
    sh:conforms false ;
    sh:result [ a sh:ValidationResult ;
            sh:focusNode <urn:uuid:dde-document-catalog-record> ;
            sh:resultMessage "DDE metadata record must declare conformance to at least two profiles, including cdif:profile_ddeCDIF" ;
            sh:resultPath dcterms:conformsTo ;
            sh:resultSeverity sh:Violation ;
            sh:sourceConstraintComponent sh:MinCountConstraintComponent ;
            sh:sourceShape [ sh:message "DDE metadata record must declare conformance to at least two profiles, including cdif:profile_ddeCDIF" ;
                    sh:minCount 2 ;
                    sh:path dcterms:conformsTo ] ] .

